-- Healing Mind Room 160 Farms Data (v2: Real 30 + Dummy 130 + Images)
CREATE TABLE IF NOT EXISTS "HealingFarm" (
    id SERIAL PRIMARY KEY,
    category_id INTEGER,
    farm_name VARCHAR(255),
    location VARCHAR(255),
    phone VARCHAR(50),
    description TEXT,
    original_program TEXT,
    region_zone VARCHAR(100),
    distance_guide VARCHAR(255),
    image_url TEXT,
    is_real VARCHAR(50)
);

TRUNCATE TABLE "HealingFarm" RESTART IDENTITY CASCADE;

